import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F03: 合約負債與營收能見度 - L3 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F03_合約負債與營收能見度_財務分析專家.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F03_合約負債與營收能見度_財務分析專家.md"}'),l={name:"審計報告庫/財務審計/3135_凌航/20260430/F03_合約負債與營收能見度_財務分析專家.md"};function n(o,a,s,d,h,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="f03-合約負債與營收能見度-l3-財務分析專家-審計報告" tabindex="-1">F03: 合約負債與營收能見度 - L3 財務分析專家 審計報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-l3-財務分析專家-審計報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - L3 財務分析專家 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：合約負債 6,644 萬（YoY +2,892%）占營收僅 0.86%，低基期反彈，非結構性訂單堆疊</li><li><strong>風險評級</strong>：中</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>診斷見解</strong>：合約負債從 2024 年谷底 222 萬爆發至 6,644 萬，表面動能極強，但占營收不足 1%、能見天數僅 ~2.3 天，遠低於設備業 30-60 天水位。凌航本質以短期 PO 交易為主，合約負債領先指標功能被產業結構稀釋，真正驅動營收的是記憶體價格波動。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="訂單領先指標-leading-indicator" tabindex="-1">訂單領先指標 (Leading Indicator) <a class="header-anchor" href="#訂單領先指標-leading-indicator" aria-label="Permalink to &quot;訂單領先指標 (Leading Indicator)&quot;">​</a></h3><p>合約負債與營收彈性失衡：2025Q4 合約負債 YoY +2,892%，營收 YoY +51.5%，彈性係數 56.2 遠超合理區間。主因 2024Q4 基期僅 222 萬，合約負債/營收比 0.86%，仍低於同業宇瞻、宜鼎（1-3%），客戶 prepay 意願有限。</p><h3 id="含金量分析-order-quality" tabindex="-1">含金量分析 (Order Quality) <a class="header-anchor" href="#含金量分析-order-quality" aria-label="Permalink to &quot;含金量分析 (Order Quality)&quot;">​</a></h3><p>前兩大客戶合計占營收 56.78%，均以短期銷貨為主。凌航依 IFRS 15 點時法（商品運抵時一次認列），合約負債壽命極短——出貨即消，不構成未來數季營收保障。漲價週期中客戶鎖貨預付合理，但不具結構性。</p><h3 id="產業對位-industry-context" tabindex="-1">產業對位 (Industry Context) <a class="header-anchor" href="#產業對位-industry-context" aria-label="Permalink to &quot;產業對位 (Industry Context)&quot;">​</a></h3><p>凌航合約負債占營收 0.86%，低於宇瞻（~1.5%）、宜鼎（~2.1%），與設備業差距更大。記憶體模組訂單能見度本身即為偽命題——真正決定營收的是 DRAM/NAND 現貨價格。2025Q4 營收衝高至 25.6 億，主因 DDR4 合約價季增 40-50%，與合約負債關聯薄弱。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><h3 id="空頭風險一-合約負債反彈的「低基期幻覺」" tabindex="-1">空頭風險一：合約負債反彈的「低基期幻覺」 <a class="header-anchor" href="#空頭風險一-合約負債反彈的「低基期幻覺」" aria-label="Permalink to &quot;空頭風險一：合約負債反彈的「低基期幻覺」&quot;">​</a></h3><p>2025Q4 合約負債 YoY +2,892% 的數字極具視覺衝擊力，但 2024Q4 基期僅 222 萬（占營收 0.09%），本質是從「幾乎不存在」回升至「微量存在」。若將觀察期延長至 2023Q4（2,486 萬），2025Q4 的 6,644 萬實際僅為 2.3 年前的 2.67 倍，年化複合增長率約 39%，並非持續加速。更關鍵的是，合約負債在 2024 年全年持續萎縮（2,486 萬 → 619 萬 → 222 萬），代表該科目具有高度波動性，不宜作為趨勢性判斷的可靠指標。</p><h3 id="空頭風險二-營收成長的「價格驅動」本質" tabindex="-1">空頭風險二：營收成長的「價格驅動」本質 <a class="header-anchor" href="#空頭風險二-營收成長的「價格驅動」本質" aria-label="Permalink to &quot;空頭風險二：營收成長的「價格驅動」本質&quot;">​</a></h3><p>凌航 2025 年累計營收 77.04 億（YoY +39.88%），2026Q1 月營收持續爆量（1-3 月合計 39.6 億，年增 204%）。然而，記憶體產業的價格循環具有強烈均值回歸特性。若 2026H2 DDR4/DDR5 合約價轉為持平或下跌，營收增速將面臨斷崖式放緩。合約負債的微薄水位（9 天能見度）意味著凌航幾乎沒有「價格下跌時的營收緩衝墊」——一旦漲價週期結束，營收將直接反映現貨市場的下行壓力。</p><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (TaiwanStockBalanceSheet)</strong>：OK <ul><li>CurrentContractLiabilities：2023Q4 24,859K → 2024Q4 2,221K → 2025Q4 66,443K</li><li>TotalAssets：2024Q4 2,123,434K → 2025Q4 5,178,900K</li></ul></li><li><strong>FinMind (TaiwanStockFinancialStatements)</strong>：OK <ul><li>Revenue 2025Q4：2,561,142K（YoY +51.5%）</li><li>Revenue 2025 annual：~7,704,000K（YoY +39.88%）</li></ul></li><li><strong>FinMind (TaiwanStockMonthRevenue)</strong>：OK <ul><li>2026M1：1,545,976K / M2：981,428K / M3：1,430,288K</li></ul></li><li><strong>年報 PDF (112年度)</strong>：OK <ul><li>收入認列政策：商品運抵客戶時點認列（附註四、第111頁）</li><li>合約負債定義：客戶預付款與履約義務之時間差（附註十五、第121頁）</li><li>前兩大客戶：B 客戶 33.95%、A 客戶 22.83%（第71頁）</li></ul></li><li><strong>yfinance (3135.TW)</strong>：OK，PBR 5.25、PER 25.0（2026-04-29）</li><li><strong>關鍵核對碼</strong>：合約負債 2025Q4 = 66,443K / 總資產 5,178,900K = 1.28% ✓；日均營收 = 7,704,000K / 365 = 21,107K；能見天數 = 66,443K / 21,107K = 3.15 天（修正後）</li></ul>',22)])])}const p=e(l,[["render",n]]);export{_ as __pageData,p as default};
